// WF_BUILD_SEGMENTS — splits each scene into 5/8/12s segments by emotional_beat,
// generates per-segment image_prompt via Haiku batch, inserts scene_segments rows,
// then fires /production/images. Forward-only — topic 4 stays on legacy 1-image-per-scene.
//
// Pacing rule (Wendover/Polymatter baseline):
//   data | revelation        -> 5s   (data-dense: viewer needs visual change to anchor specifics)
//   hook | tension | story   -> 8s   (default narrative cadence)
//   resolution | transition  -> 12s  (contemplative beats)
//
// Audio is the master clock. N segments per scene = ceil(audio_ms / (target*1000)).
// Each segment.duration_ms = round(audio_ms / N) so segments distribute evenly and
// sum exactly to scene's audio. Captions burn over final concat — sync preserved.

const SB = $env.SUPABASE_URL;
const SRK = $env.SUPABASE_SERVICE_ROLE_KEY;
const ANON = $env.SUPABASE_ANON_KEY;
const AK = $env.ANTHROPIC_API_KEY;
const sbHeaders = { apikey: ANON, Authorization: 'Bearer ' + SRK, 'Content-Type': 'application/json' };

const body = $('Webhook Trigger').first().json.body || {};
const topicId = body.topic_id;
if (!topicId) throw new Error('topic_id missing from webhook body');

// Pacing map
function targetSecondsForBeat(beat) {
  const b = (beat || 'story').toLowerCase();
  if (b === 'data' || b === 'revelation') return 5;
  if (b === 'resolution' || b === 'transition') return 12;
  return 8; // hook | tension | story | unknown
}

// 1. Load all scenes for this topic
const scenesResp = await fetch(SB + '/rest/v1/scenes?topic_id=eq.' + topicId + '&select=id,scene_number,scene_id,audio_duration_ms,emotional_beat,narration_text,image_prompt&order=scene_number.asc', { headers: sbHeaders });
if (!scenesResp.ok) throw new Error('Scene fetch failed: ' + scenesResp.status);
const scenes = await scenesResp.json();
console.log('Loaded ' + scenes.length + ' scenes');

// Skip if segments already exist (idempotent / resume-safe)
const existResp = await fetch(SB + '/rest/v1/scene_segments?topic_id=eq.' + topicId + '&select=id&limit=1', { headers: sbHeaders });
const existing = await existResp.json();
if (Array.isArray(existing) && existing.length > 0) {
  console.log('scene_segments already exist for topic ' + topicId + ' — skipping rebuild');
  return [{ json: { topic_id: topicId, skipped: true, reason: 'already_built' } }];
}

// 2. Compute segments per scene (timing only, no prompts yet)
const segmentPlans = [];
for (const scene of scenes) {
  const audioMs = scene.audio_duration_ms || 0;
  if (audioMs < 1000) continue; // skip degenerate scenes
  const targetSec = targetSecondsForBeat(scene.emotional_beat);
  const targetMs = targetSec * 1000;
  const N = Math.max(1, Math.ceil(audioMs / targetMs));
  const eachMs = Math.round(audioMs / N);
  // Distribute narration words proportionally
  const words = (scene.narration_text || '').split(/\s+/).filter(Boolean);
  const wordsPerSeg = Math.ceil(words.length / N);
  for (let i = 0; i < N; i++) {
    const startWord = i * wordsPerSeg;
    const endWord = Math.min(words.length, (i + 1) * wordsPerSeg);
    const excerpt = words.slice(startWord, endWord).join(' ');
    const isLast = (i === N - 1);
    const dur = isLast ? (audioMs - eachMs * (N - 1)) : eachMs;
    segmentPlans.push({
      scene_id: scene.id,
      topic_id: topicId,
      project_id: undefined, // filled below
      scene_number: scene.scene_number,
      segment_number: i + 1,
      start_offset_ms: i * eachMs,
      duration_ms: dur,
      narration_excerpt: excerpt,
      emotional_beat: scene.emotional_beat,
      target_seconds: targetSec
    });
  }
}
console.log('Computed ' + segmentPlans.length + ' segments across ' + scenes.length + ' scenes');

// Pull project_id once
let projectId = null;
if (scenes[0]) {
  const t = await fetch(SB + '/rest/v1/topics?id=eq.' + topicId + '&select=project_id', { headers: sbHeaders });
  const tj = await t.json();
  projectId = (Array.isArray(tj) && tj[0]) ? tj[0].project_id : null;
}
for (const p of segmentPlans) p.project_id = projectId;

// 3. Haiku batch call — one prompt for all segments at once
const classifierSystem = 'You are a precise visual-routing classifier and image-prompt generator for documentary thumbnails. Given a scene\'s parent narration plus a list of segment excerpts, generate a per-segment image_prompt that depicts a CONCRETE noun/action LITERALLY appearing in that segment\'s excerpt. Do not invent imagery (people, professions, objects, settings) the excerpt does not mention. If the excerpt is abstract (emotion, statistic, policy), depict a relevant ACTION or PROP from the words on the page — never a vague figure with abstract lighting. Each prompt: 30-50 words, cinematic structure [SUBJECT]+[ENVIRONMENT]+[LIGHTING]+[COMPOSITION]+[MOOD]. Return ONLY a JSON array.';

// Group by scene, send one batch prompt with all scenes
const batchInput = scenes.map(s => {
  const segsForScene = segmentPlans.filter(p => p.scene_id === s.id);
  return {
    scene_number: s.scene_number,
    parent_narration: (s.narration_text || '').substring(0, 800),
    parent_image_prompt: s.image_prompt || '',
    segments: segsForScene.map(seg => ({
      segment_number: seg.segment_number,
      excerpt: seg.narration_excerpt.substring(0, 240)
    }))
  };
}).filter(s => s.segments.length > 0);

const userPrompt = 'Generate per-segment image_prompts. For EACH segment provide:\n' +
  '- scene_number, segment_number, image_prompt (30-50 words), key_visual_anchor (1-6 words naming the concrete subject literally appearing in the excerpt), requires_text_rendering (true only if scene meaning depends on legible text in the image — chart labels, document headlines, app/UI text, signage; false for incidental papers).\n\n' +
  'Return ONLY a JSON array of {scene_number, segment_number, image_prompt, key_visual_anchor, requires_text_rendering} objects. No prose, no markdown.\n\n' +
  'INPUT:\n' + JSON.stringify(batchInput, null, 0);

console.log('Haiku batch call: ' + batchInput.length + ' scenes, ' + segmentPlans.length + ' segments, prompt ~' + Math.round(userPrompt.length / 1000) + 'K chars');

const claudeResp = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: { 'x-api-key': AK, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' },
  body: JSON.stringify({
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 32000,
    system: classifierSystem,
    messages: [{ role: 'user', content: userPrompt }]
  })
});
if (!claudeResp.ok) {
  const err = await claudeResp.text();
  throw new Error('Haiku call failed: ' + claudeResp.status + ' ' + err.substring(0, 300));
}
const claudeJson = await claudeResp.json();
const rawText = claudeJson.content[0].text;
console.log('Haiku response: ' + rawText.length + ' chars  in=' + claudeJson.usage.input_tokens + ' out=' + claudeJson.usage.output_tokens);

// Parse
const cleaned = rawText.replace(/^```(?:json)?\s*/m, '').replace(/\s*```$/m, '').trim();
const si = cleaned.indexOf('['), ei = cleaned.lastIndexOf(']');
if (si < 0 || ei <= si) throw new Error('No JSON array in Haiku response: ' + cleaned.substring(0, 300));
const classifications = JSON.parse(cleaned.substring(si, ei + 1));
console.log('Parsed ' + classifications.length + ' classifications');

// Index by (scene_number, segment_number)
const clsMap = {};
for (const c of classifications) {
  clsMap[c.scene_number + '_' + c.segment_number] = c;
}

// 4. Build INSERT rows
const rows = segmentPlans.map(p => {
  const c = clsMap[p.scene_number + '_' + p.segment_number] || {};
  return {
    scene_id: p.scene_id,
    topic_id: p.topic_id,
    project_id: p.project_id,
    segment_number: p.segment_number,
    start_offset_ms: p.start_offset_ms,
    duration_ms: p.duration_ms,
    narration_excerpt: p.narration_excerpt.substring(0, 1000),
    image_prompt: c.image_prompt || (p.narration_excerpt.substring(0, 80) + ' — documentary scene, cinematic lighting, moody atmosphere'),
    key_visual_anchor: (c.key_visual_anchor || '').substring(0, 64),
    requires_text_rendering: c.requires_text_rendering === true,
    image_status: 'pending',
    clip_status: 'pending'
  };
});

// 5. Bulk insert (chunk into batches of 50 to avoid PostgREST payload limits)
const CHUNK = 50;
let inserted = 0;
for (let i = 0; i < rows.length; i += CHUNK) {
  const batch = rows.slice(i, i + CHUNK);
  const insResp = await fetch(SB + '/rest/v1/scene_segments', {
    method: 'POST',
    headers: { ...sbHeaders, Prefer: 'return=minimal' },
    body: JSON.stringify(batch)
  });
  if (!insResp.ok) {
    const err = await insResp.text();
    throw new Error('scene_segments insert failed at chunk ' + (i / CHUNK) + ': ' + err.substring(0, 300));
  }
  inserted += batch.length;
}
console.log('Inserted ' + inserted + ' scene_segments rows');

// 6. Mark scenes.uses_segments = true
await fetch(SB + '/rest/v1/scenes?topic_id=eq.' + topicId, {
  method: 'PATCH',
  headers: { ...sbHeaders, Prefer: 'return=minimal' },
  body: JSON.stringify({ uses_segments: true })
});

// 7. Update topic telemetry
const avgDur = Math.round(rows.reduce((s, r) => s + r.duration_ms, 0) / rows.length);
await fetch(SB + '/rest/v1/topics?id=eq.' + topicId, {
  method: 'PATCH',
  headers: { ...sbHeaders, Prefer: 'return=minimal' },
  body: JSON.stringify({ segment_count: rows.length, avg_segment_duration_ms: avgDur })
});

return [{ json: { topic_id: topicId, scenes: scenes.length, segments: rows.length, avg_segment_duration_ms: avgDur } }];

